sp_widget.client_script:
api.controller=function($scope, $filter, spUtil,spModal) {
  /* widget controller */
  var c = this;

	$scope.loadingData = true;
	var loadRowCount = c.data.row_count;
	_loadData();

	spUtil.recordWatch($scope, c.data.table, c.data.filter, function(name) {
		$scope.loadingData = true;
		_loadData();
	});

	function _loadData(){
		$scope.server.update().then(function() {
			$scope.loadingData = false;
		});		
	}


	// *******************************************
	// START EDIT OOO MENU OPTION
	// *******************************************
	$scope.editOOO = function(item){
		spModal.open({
			message: '',
			backdrop: 'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: c.data.table,
				sys_id: item.sys_id,
				hideRelatedLists: false,
				// STRY0115843
				omitHeader: true,
				bifold: false,
				hideAttachmentBtn: true,
				isModal: true
			},
			shared: {},
			size: 'lg',
			// DFCT0011320
			buttons: [''],
			// 2.7.2 | 2022-01-13 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
			footerStyle: {
				'display': 'none'
			}
		});
	};
	// *******************************************
	// END EDIT OOO MENU OPTION
	// *******************************************

	// *******************************************
	// START DELETE OOO MENU OPTION
	// *******************************************
	$scope.deleteOOO = function(item){
		var startDate = item.startDateLong; //formatDate(item.u_start_date.display_value.substring(0,10), 'MMMM d, yyyy');
		var endDate = item.endDateLong; //formatDate(item.u_end_date.display_value.substring(0,10), 'MMMM d, yyyy');

		spModal.open({
            title: c.data.deleteTitle,
            backdrop: 'static',
            widget: 'tasker_modal_delete_prompt',
            widgetInput: {
							'oooSysId': item.sys_id,
							'oooStartDate': startDate,
							'oooEndDate': endDate
            },
            buttons: [],
			// Hide the <div> with class modal-footer that gets auto inserted from spModal, adds an element style
			footerStyle: { 'display': 'none' }
        }).then(function() {
            //jslog('numberofsubtasks');
        });
	};
	// *******************************************
	// END DELETE OOO MENU OPTION
	// *******************************************

	// *******************************************
	// START VIEW HISTORY OOO MENU OPTION
	// *******************************************
	$scope.viewHistory = function(item){
		$scope.$emit("$oooViewHistory");
	};
	// *******************************************
	// END VIEW HISTORY OOO MENU OPTION
	// *******************************************
};

sp_widget.css:
.ooo-scheduled-row {
  width: 100%;
  height: 80px;
  background-color: #f5f5f5;
  border-radius: 10px;
  box-shadow:0px 0px 0px 2px #f5f5f5 inset;
} 
.ooo-scheduled-row:hover {
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
  cursor: pointer;
}

.ooo-scheduled-row:focus {
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-scheduled-row:active {
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
}

.ooo-scheduled-row:disabled {
  background-color: #f5f5f5;
}

.ooo-scheduled-columnheader {
  font-family: SourceSansPro, Helvetica, Arial, sans-serif;
  font-size: 14px;
  color: #757575;
  padding: 10px 0px 0px 10px;
}

.ooo-scheduled-columnheader:disabled {
  color: #757575;
  padding: 10px 0px 0px 10px;
}

.ooo-scheduled-datelabel {
  font-family: SourceSansPro, Helvetica, Arial, sans-serif; 
  font-size: 14px; 
  color: #000000; 
  font-weight: 600;
  padding: 0px 0px 0px 10px;
}

.ooo-scheduled-datelabel:disabled {
  color: #757575;
}

.ooo-scheduled-ellipsesbtn {
  width: 24px;
  height: 24px;
  background-color: #f5f5f5;
  border-radius: 5px;
  box-shadow:0px 0px 0px 2px #f5f5f5 inset;
}

.ooo-scheduled-ellipsesbtn:hover {
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
  cursor: pointer;
}

.ooo-scheduled-ellipsesbtn:focus {
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-scheduled-ellipsesbtn:active {
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
/* Special License Rights
*  The Government's rights to use, display, or disclose this software are restricted.
*  Any reproduction of computer software, computer software documentation,
*  or portions thereof marked with this legend must also reproduce the markings. */
// 2.8.1 | 2022-11-10 | raj  | STRY0132270 - Tasker User Profile- New Component- "Out of Office Schedule" - OOO Scheduled Widget
//                                      New Widget
// 2.8.1 | 2022-11-12 | raj  | STRY0131195 - Delete OOO Schedule Confirmation Modal
//                                         Changes made in Server Script, Client Script, opened the tasker delete prompt widget from delete click
// Script Continued Below
(function($sp, input, data, options, gs) {
	main();

	function main() {

		data.isModal = (input || {}).isModal || (options || {}).isModal || $sp.getParameter("isModal") || false;
		data.isTopWidget = (input || {}).isTopWidget || (options || {}).isTopWidget || $sp.getParameter("isTopWidget") || false;
		data.bifold = (input || {}).bifold || (options || {}).bifold || $sp.getParameter("bifold") || false;	
		data.user = (input || {}).user || (options || {}).user || $sp.getParameter("user_id") || gs.getUserID();
		data.table = "x_153465_discovert_out_of_office";
		data.list = [];
		data.fields = "u_start_date,u_end_date,sys_created_on,sys_updated_on,u_out_of_office_message";
    data.fields_array = data.fields.split(',');
		data.column_labels = {};
		data.filter = "^u_user=" + data.user + "^u_end_date>=javascript:gs.endOfToday()";

		data.column_labels = _loadColumnLabels();
		data.list = _loadScheduledOOO();
		_getMessages();
	}

	function _getMessages(){
		data.ellipsesIcon = "Ellipses16.svg";
		data.editIcon = "Edit16.svg";
		data.deleteIcon = "Delete16.svg";
		data.historyIcon = "History16.svg";
		data.deleteTitle = gs.getMessage("Tasker - Confirm Delete Schedule");
	}

	function _loadScheduledOOO(){
		var list = [];
		var gr_ooo = new GlideRecordSecure(data.table);

		gr_ooo.addEncodedQuery(data.filter);
		gr_ooo.query();

		while(gr_ooo.next()){
			data.canWrite = gr_ooo.canWrite();
			data.canDelete = gr_ooo.canDelete();

			var record = {};
			$sp.getRecordElements(record,gr_ooo,data.fields);
			record.sys_id = gr_ooo.getValue('sys_id');

			var gDateStart = new GlideDate();
			gDateStart.setDisplayValue(gr_ooo.getDisplayValue("u_start_date"));
			record.startDateLong =  gDateStart.getByFormat('MMMM d, y');//now use the date2 to set the field value
			var gDateEnd = new GlideDate();
			gDateEnd.setDisplayValue(gr_ooo.getDisplayValue("u_end_date"));
			record.endDateLong =  gDateEnd.getByFormat('MMMM d, y');//now use the date2 to set the field value

			list.push(record);
		}
		return list;
	}

	function _loadColumnLabels(){
		var column_labels = {};
    // use GlideRecord to get field labels vs. GlideRecordSecure
    var grForLabels = new GlideRecord(data.table);
    for (var i in data.fields_array) {
        var field = data.fields_array[i];
        var ge = grForLabels.getElement(field);

        //---------------------------------------------
        //STRY0071963: Servcienow Server JavaScript error getLabel in object null.
        /*if (ge == null)
        	continue;

        column_labels[field] = ge.getLabel();
        */
        try {
            if (ge == null)
                continue;

            column_labels[field] = ge.getLabel();
        } catch (ex) {
            var message = ex.message;
            gs.error("Tasker error in Scheduled Out of Office Widget - field : " + message + " | field: " + field + " | ge: " + ge + " | i :" + i);
        }
        //---------------------------------------------
    }
		return column_labels;

	}

	// copy to data from input or options
	function optCopy(names) {
		names.forEach(function(name) {
			data[name] = input[name] || options[name];
		});
	}

	// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; added
	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}
})($sp, input, data, options, gs);
